#!/usr/bin/env node
// Deploy MultiSend contract using OKX Agentic Wallet
// Usage: npm run deploy:okx

import 'dotenv/config';
import { execSync } from 'child_process';
import fs from 'fs';
import path from 'path';

// Contract bytecode - compiled from MultiSend.sol
const MULTISEND_BYTECODE = "";

async function deployWithOKX() {
  console.log('🚀 Deploying MultiSend contract via OKX Agentic Wallet...\n');
  
  // Check OKX credentials
  const apiKey = process.env.OKX_API_KEY;
  const secretKey = process.env.OKX_SECRET_KEY;
  const passphrase = process.env.OKX_PASSPHRASE;
  
  if (!apiKey || !secretKey || !passphrase) {
    console.error('❌ OKX credentials not set');
    console.log('Set these in your .env:');
    console.log('OKX_API_KEY=your_api_key');
    console.log('OKX_SECRET_KEY=your_secret');
    console.log('OKX_PASSPHRASE=your_passphrase');
    process.exit(1);
  }
  
  try {
    // Use OKX CLI to deploy contract
    const deployScript = `
$env:OKX_API_KEY = "${apiKey}"
$env:OKX_SECRET_KEY = "${secretKey}"
$env:OKX_PASSPHRASE = "${passphrase}"
onchainos wallet contract-call --chain 196 --to 0x0000000000000000000000000000000000000000 --input-data ${MULTISEND_BYTECODE} --amt 0
`;
    
    fs.writeFileSync('deploy_temp.ps1', deployScript);
    
    console.log('📦 Deploying contract...');
    console.log('This will create the MultiSend contract on X Layer\n');
    
    const result = execSync('powershell -ExecutionPolicy Bypass -File deploy_temp.ps1', { 
      encoding: 'utf8',
      stdio: 'inherit'
    });
    
    // Clean up
    fs.unlinkSync('deploy_temp.ps1');
    
  } catch (error) {
    console.error('\n❌ Deployment failed:', error.message);
    console.log('\nNote: Contract deployment via wallet may require manual steps.');
    console.log('Alternative: Deploy using Hardhat with PRIVATE_KEY');
    process.exit(1);
  }
}

deployWithOKX();
